import React, { useState } from 'react';
import axios from 'axios';

function CreateResume() {

  const [resume, setResume] = useState({
    fullName: '',
    email: '',
    phone: '',
    summary: '',
    skills: '',
    education: '',
    experience: '',
    projects: '',
    languages: '',
    hobbies: ''
  });

  const [aiInput, setAiInput] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setResume({
      ...resume,
      [e.target.name]: e.target.value
    });
  };

  // ================= SAVE RESUME =================
  const saveResume = () => {
    console.log(resume);
    alert("Resume Saved (Connect API here)");
  };

  // ================= CHATGPT FUNCTION =================
  const askAI = async () => {
    setLoading(true);
    setAiResponse('');

    try {
      const res = await axios.post(
        "https://api.openai.com/v1/chat/completions",
        {
          model: "gpt-4o-mini",
          messages: [
            {
              role: "system",
              content: "You are a professional resume assistant. Help improve resume content."
            },
            {
              role: "user",
              content: aiInput
            }
          ]
        },
        {
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer YOUR_OPENAI_API_KEY`
          }
        }
      );

      setAiResponse(res.data.choices[0].message.content);

    } catch (error) {
      console.log(error);
      setAiResponse("Error: Unable to get AI response");
    }

    setLoading(false);
  };

  // ================= AUTO GENERATE SUMMARY =================
  const generateSummary = async () => {
    setAiInput(`Write a professional resume summary for:
Name: ${resume.fullName}
Skills: ${resume.skills}
Experience: ${resume.experience}`);

    await askAI();
  };

  return (
    <div className="container mt-4">

      <h2>Create Resume</h2>

      <div className="row">

        {/* ================= RESUME FORM ================= */}
        <div className="col-md-6">

          <input name="fullName" placeholder="Full Name" className="form-control mb-2" onChange={handleChange} />
          <input name="email" placeholder="Email" className="form-control mb-2" onChange={handleChange} />
          <input name="phone" placeholder="Phone" className="form-control mb-2" onChange={handleChange} />

          <textarea name="summary" placeholder="Summary" className="form-control mb-2" onChange={handleChange}></textarea>

          <input name="skills" placeholder="Skills" className="form-control mb-2" onChange={handleChange} />
          <input name="education" placeholder="Education" className="form-control mb-2" onChange={handleChange} />
          <input name="experience" placeholder="Experience" className="form-control mb-2" onChange={handleChange} />
          <input name="projects" placeholder="Projects" className="form-control mb-2" onChange={handleChange} />
          <input name="languages" placeholder="Languages" className="form-control mb-2" onChange={handleChange} />
          <input name="hobbies" placeholder="Hobbies" className="form-control mb-2" onChange={handleChange} />

          <button className="btn btn-success w-100 mt-2" onClick={saveResume}>
            Save Resume
          </button>

        </div>

        {/* ================= AI CHAT PANEL ================= */}
        <div className="col-md-6">

          <h4>🤖 AI Resume Assistant</h4>

          <textarea
            className="form-control mb-2"
            rows="4"
            placeholder="Ask AI (e.g. Write professional summary for Java developer)"
            value={aiInput}
            onChange={(e) => setAiInput(e.target.value)}
          />

          <button className="btn btn-primary me-2" onClick={askAI}>
            Ask AI
          </button>

          <button className="btn btn-warning" onClick={generateSummary}>
            Generate Summary
          </button>

          <hr />

          {loading ? (
            <p>Loading AI response...</p>
          ) : (
            <div style={{ whiteSpace: "pre-wrap" }}>
              {aiResponse}
            </div>
          )}

        </div>

      </div>

    </div>
  );
}

export default CreateResume;
